#include <stdio.h>

int main() {
    int n, x;
    scanf("%d", &n);
    scanf("%d", &x);

    int patterns[3][6] = {
        {0, 1, 2, 2, 1, 0},
        {1, 0, 0, 1, 2, 2},
        {2, 2, 1, 0, 0, 1}
    };

    n %= 6;
    for (int i = 0; i < 3; i++) {
        if (patterns[i][n] == x) {
            printf("%d\n", i);
        }
    }

    return 0;
}
